INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Habits, Dailies and To-Dos$q$, $q$Three distinct task types model repeatable behaviors, scheduled routines and one-off items differently rather than forcing everything into a single generic list.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$RPG avatar progression$q$, $q$Completing tasks earns gold, experience and item drops that level up an avatar with classes, gear, pets and mounts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Parties$q$, $q$Small accountability groups of friends team up to battle in-game bosses through completed real-life tasks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Guilds and Challenges$q$, $q$Topic-based communities let members share task lists and hold each other accountable through joinable Challenges.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Custom rewards column$q$, $q$Users define their own real-life rewards that can be purchased with in-game gold earned from completed tasks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Cross-platform sync$q$, $q$Native iOS and Android apps sync instantly with the web app so progress stays consistent across devices.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Open API$q$, $q$A public API lets developers build integrations, browser extensions and community tools on top of Habitica.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Avatar customization$q$, $q$Hairstyles, skin tones, outfits and accessibility options like wheelchairs let users personalize their in-game character.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Core app is entirely free with no feature paywall$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Strong social accountability through Parties and Guilds$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Fully open source and transparent development$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Available on web, iOS and Android with instant sync$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Explicitly not pay-to-win, so free users are not disadvantaged$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$RPG-style interface has a learning curve compared to plain to-do apps$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Gamified framing can feel too playful for users who want a minimalist tool$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Losing health points for missed Dailies can add stress for some users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Reminder and notification features are less robust than dedicated task apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$In-game currency system (gold versus Gems) can be confusing at first$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Is Habitica free to use?$q$, $q$Yes, Habitica's core habit tracker, to-do list, and RPG gamification system are entirely free. An optional $5 per month subscription unlocks extra Gems, faster item drops and subscriber-exclusive cosmetics.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$What is Habitica used for?$q$, $q$Habitica is used for building habits, tracking recurring routines, and managing to-do lists by turning task completion into RPG-style progression with experience points, gold and collectible items.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Is Habitica open source?$q$, $q$Yes, Habitica's codebase has been open source since its early days and is hosted publicly on GitHub, allowing community contributions and transparency into how the app works.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$What happens if I miss a Daily task in Habitica?$q$, $q$Missing a scheduled Daily causes your avatar to lose health points. If health reaches zero, the avatar suffers a small in-game penalty, but there is no real-world consequence beyond that.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Does Habitica have a mobile app?$q$, $q$Yes, Habitica has official native apps for both iOS and Android that sync in real time with the web version.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Can I use Habitica with friends?$q$, $q$Yes, Habitica's Party feature lets small groups of friends team up to battle in-game bosses through completed tasks, and Guilds let users join larger interest-based communities and Challenges.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Personal habit building$q$, $q$Individuals use Habitica's Habits and Dailies to build consistency around exercise, sleep, study or other routines using game-based rewards.$q$, $q$Individuals working on personal productivity and habit formation$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Gamified task management for students and neurodivergent users$q$, $q$Students and users with ADHD use Habitica's immediate feedback loops and visual progression to stay engaged with coursework and daily responsibilities.$q$, $q$Students and neurodivergent individuals who benefit from externalized structure$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Group accountability$q$, $q$Friend groups and online communities use Parties and Guild Challenges to hold each other accountable to shared goals.$q$, $q$Friend groups, support communities and hobby groups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, NULL, $q$["Full Habits, Dailies and To-Dos task system","Avatar creation and RPG progression","Parties and Guilds for social accountability","Cross-device sync across web, iOS and Android","Public API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$Subscription$q$, $q$$5/month (or $48/year on the 12-month plan, about $4/month)$q$, $q$Monthly, quarterly, semi-annual or annual$q$, NULL, $q$["Higher monthly Gem purchase cap, up to 50 Gems","Doubled daily item drop rate","Subscriber-exclusive monthly mystery item","Exclusive Royal Purple Jackalope pet","Ability to buy Gems with in-game gold"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Habitica is a free, open source productivity app that reframes habit-building and task management as a role-playing game. Instead of a plain checklist, users maintain an avatar that gains experience, gold and gear for real-life tasks completed, and loses health for missed recurring commitments.$q$, $q$Originally launched in 2012 as HabitRPG by developer Tyler Renelle, the project was renamed Habitica in 2015 after incorporating as a company in 2014. It remains privately held and headquartered in Santa Monica, California, with an open source codebase maintained on GitHub.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Habitica splits tasks into Habits, Dailies and To-Dos, each modeled differently so recurring routines, one-off errands and repeatable behaviors are tracked in ways that fit how they actually work in real life. Completing tasks earns gold, experience and item drops that feed into avatar progression, classes, equipment, pets and mounts.$q$, $q$Social features include Parties, small groups that team up to battle bosses through completed tasks, and Guilds, topic-based communities that support Challenges, shared task lists members can opt into together. A public API, cross-device sync, and customizable avatars round out the feature set.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Habitica's core app is entirely free, with no feature paywall on the main task and gamification loop. An optional $5 per month subscription, discounted to about $4 per month on annual billing, raises the monthly Gem purchase cap, doubles daily item drops, and unlocks subscriber-exclusive cosmetics.$q$, $q$Habitica is explicitly designed to not be pay-to-win: subscribers do not progress faster through content than free users, so the subscription functions mainly as a way to support development and access convenience and cosmetic perks.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
