INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4c66c0bf-66e6-4947-82a4-244a69ecb504', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Appointment scheduling and calendar$q$, $q$Online booking pages, automated email and SMS reminders, and a shared calendar reduce no-shows and administrative overhead.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Automated Medicare and rebate processing$q$, $q$Medicare, ECLIPSE, NDIS, DVA, Workcover and TAC rebates can be configured to submit automatically during or after appointments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Clinical notes and 700+ templates$q$, $q$Built-in clinical tools and templates cover documentation needs across 90+ healthcare professions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Built-in telehealth$q$, $q$Video and phone consultations run directly inside Halaxy, with optional integration with Zoom or Coviu.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Invoicing and payments$q$, $q$Automated invoicing, payment collection and patient account management are included in the free core platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Two-way calendar sync$q$, $q$A paid add-on that keeps Halaxy's calendar synced bidirectionally with external calendar tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Public API$q$, $q$A paid subscription feature that lets practices integrate Halaxy with other systems.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Mobile apps$q$, $q$iOS and Android apps let practitioners and patients manage bookings and records on the go.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Core software is completely free with no subscription requirement$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Automates Medicare, NDIS and DVA rebate processing without manual work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Supports over 90 allied health and medical professions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Built-in telehealth included at no extra software cost$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Unlimited practitioners and locations on the free tier$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Pay-per-use credit system can become costly for high-volume practices$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Primarily optimized for Australian healthcare compliance, with more limited UK and Ireland support$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Key structural features like the API and two-way sync require a paid subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Credit-based billing model has a learning curve for new users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Some advanced features depend on purchasing credits in bulk to get better rates$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Is Halaxy really free?$q$, $q$Yes, Halaxy's core practice management platform, including scheduling, patient records, clinical notes and invoicing, is free with no sign-up cost or credit card required. Practices only pay for optional credits and subscription add-ons.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$What is Halaxy used for?$q$, $q$Halaxy is used by health practitioners to manage appointment scheduling, clinical documentation, billing, insurance and government rebates, and telehealth consultations in one platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Does Halaxy process Medicare rebates automatically?$q$, $q$Yes, Halaxy can be configured to automatically submit Medicare and other rebates at a set time during or after an appointment, with responses and fund transfers happening without manual intervention.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Does Halaxy support telehealth?$q$, $q$Yes, Halaxy includes a built-in telehealth module for video and phone consultations, and can also connect to external platforms like Zoom or Coviu.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$What are Halaxy credits used for?$q$, $q$Halaxy credits are a pay-as-you-go currency used for actions like SMS reminders, rebate processing, telehealth minutes and AI Scribe transcription.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Which countries does Halaxy support?$q$, $q$Halaxy was built primarily for the Australian healthcare system and its rebate schemes, and has since expanded to support practices in the UK and Ireland.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Solo allied health practitioner$q$, $q$A single practitioner uses Halaxy's free core platform to manage bookings, clinical notes and invoicing without paying for software.$q$, $q$Solo practitioners such as psychologists, physiotherapists or dietitians$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Multi-practitioner clinic billing automation$q$, $q$Clinics use Halaxy's automated Medicare, NDIS and DVA rebate processing to reduce administrative billing work across multiple practitioners.$q$, $q$Multi-practitioner clinics handling government and insurance billing$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Telehealth-first practice$q$, $q$Practices delivering remote care use Halaxy's built-in telehealth alongside integrated scheduling and rebate processing.$q$, $q$Practitioners offering remote or hybrid telehealth consultations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Free Core Platform$q$, $q$$0$q$, $q$Free, no credit card required$q$, NULL, $q$["Calendar and appointment scheduling","Patient records and clinical notes","700+ clinical tools and templates","Invoicing and online booking","Unlimited practitioners and locations","Support for 90+ health professions"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Subscription Features$q$, $q$From A$25/month$q$, $q$Monthly$q$, NULL, $q$["Two-way calendar sync","White label branding","Halaxy API access","E-script integrations","Dedicated practice phone number"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$Pay-As-You-Go Credits$q$, $q$Approximately A$0.15 to A$0.22 per credit$q$, $q$Usage-based, bulk discounts available$q$, NULL, $q$["SMS reminders","Telehealth minutes","Medicare and other rebate processing","AI Scribe transcription"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Halaxy is a free, cloud-based practice management platform for health practitioners, combining scheduling, clinical documentation, billing and telehealth in one system. It supports more than 90 healthcare professions and places no limit on practitioners or locations on its free tier.$q$, $q$Founded in Melbourne, Australia, and launched online in 2012 (originally as Healthkit before rebranding to Halaxy in 2019), the company has since expanded support into the UK and Ireland markets alongside its core Australian base.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Halaxy's free core includes calendar scheduling with automated reminders, clinical notes, over 700 clinical templates, invoicing and online patient booking. Its standout capability is automated processing of Medicare, NDIS, DVA, Workcover and TAC rebates without manual portal submission.$q$, $q$Built-in telehealth supports video and phone consultations directly inside the platform, and paid add-ons unlock two-way calendar sync, white label branding, API access and e-script integrations for practices that need deeper customization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Halaxy's core software is free with no sign-up cost or credit card requirement. Usage-based Pay-As-You-Go credits, roughly A$0.15 to A$0.22 each, cover actions like SMS reminders, rebate processing and telehealth minutes.$q$, $q$Subscription Features, starting around A$25 per month, unlock structural capabilities like the API, two-way sync and white label branding that aren't available through credits alone.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fddf95b3-6124-4cb3-8919-8d1df1119657', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Incident and major incident management$q$, $q$Centralized ticket logging, prioritization, SLA tracking and escalation for both routine and major incidents.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Service catalog and self-service portal$q$, $q$A configurable request catalog with automated approval routing and a self-service portal for end users.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Change management with CAB workflows$q$, $q$Supports standard, normal and emergency changes with Change Advisory Board review processes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Problem management$q$, $q$Root cause analysis and known error documentation to prevent recurring incidents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$CMDB and asset management$q$, $q$Tracks configuration items, assets and their service dependencies in one place.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Halo AI$q$, $q$Built-in AI for automated ticket triage, categorization, prioritization and response drafting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$1,000+ built-in reports$q$, $q$Extensive out-of-the-box reporting plus custom dashboard building for IT and management visibility.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Flexible deployment$q$, $q$Available as cloud SaaS, private cloud, or fully on-premise to meet compliance and data residency needs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$All-inclusive pricing with no separate module fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Flexible deployment options including on-premise and private cloud$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Extensive out-of-the-box reporting library$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$AI-assisted ticket triage and automation via Halo AI$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Scales from smaller IT teams to large enterprise deployments$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Pricing is not published and requires a sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Breadth of ITIL functionality can create a steeper configuration curve$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Per-agent pricing can become costly for larger agent counts$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Advanced ITIL workflows may require significant onboarding time$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Third-party pricing estimates vary, making budgeting less predictable upfront$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$What is HaloITSM used for?$q$, $q$HaloITSM is used by IT teams to manage incidents, service requests, changes, problems and assets in a single ITIL-aligned service management platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$How much does HaloITSM cost?$q$, $q$HaloITSM uses custom per-agent monthly pricing based on team size, deployment method and contract length; third-party estimates put typical costs around $50 to $70 per agent per month with all modules included.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Does HaloITSM offer a free trial?$q$, $q$Yes, HaloITSM offers a 30-day free trial with full access to its features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$What is Halo AI?$q$, $q$Halo AI is HaloITSM's built-in artificial intelligence layer that automates ticket categorization, prioritization and response drafting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Can HaloITSM be deployed on-premise?$q$, $q$Yes, HaloITSM supports cloud, private cloud and fully on-premise deployment options.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Who owns HaloITSM?$q$, $q$HaloITSM is developed by Halo Service Solutions, a UK company founded in 1994 as NetHelpDesk that rebranded to Halo in 2019.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Enterprise ITIL service desk$q$, $q$Enterprise IT teams implement HaloITSM to run compliant incident, request, change and problem management processes.$q$, $q$Enterprise IT departments adopting ITIL practices$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Managed service provider operations$q$, $q$MSPs use Halo's product family, including HaloITSM and HaloPSA, to support multiple client organizations from one platform.$q$, $q$Managed service providers supporting multiple clients$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Regulated sector service management$q$, $q$Government, healthcare and education organizations use HaloITSM's on-premise and private cloud options to meet compliance requirements.$q$, $q$Public sector and regulated industry IT teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$HaloITSM (Per-Agent)$q$, $q$Custom quote, typically around $50 to $70 per agent per month$q$, $q$Monthly or annual contract$q$, NULL, $q$["All ITIL modules included with no separate module fees","Incident, request, change and problem management","CMDB and asset management","Halo AI ticket triage and automation","1,000+ built-in reports","Cloud, private cloud or on-premise deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$Enterprise Package$q$, $q$Custom, promoted as an all-inclusive offer for qualifying organizations$q$, $q$Custom contract$q$, NULL, $q$["Full platform access across all modules","Dedicated enterprise support","Flexible deployment options"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HaloITSM is an all-inclusive, ITIL-aligned IT service management platform that bundles incident, request, change, problem, asset and knowledge management into one product rather than separately priced modules.$q$, $q$It is developed by Halo Service Solutions, a UK company founded in 1994 as NetHelpDesk that rebranded to Halo in 2019 after a full browser-based product rewrite, and is headquartered in Stowmarket, England, with over 250 employees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities span incident and major incident management with SLA tracking, a self-service catalog with approval routing, change management with CAB review workflows, problem management with root cause analysis, and a CMDB for asset and dependency tracking.$q$, $q$Halo AI adds automated ticket triage, categorization and drafting assistance, while the platform offers over 1,000 built-in reports and flexible deployment across cloud, private cloud or fully on-premise environments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HaloITSM uses custom, per-agent monthly pricing rather than published tiers, with quotes depending on team size, deployment method and contract length; third-party estimates put typical costs around $50 to $70 per agent per month with all modules included.$q$, $q$Volume discounts apply at scale, and the company offers a 30-day free trial with full feature access along with a promoted all-inclusive enterprise package for qualifying organizations.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c110df5-bfa6-4663-9dad-5ea512a9a23a', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Broad format support$q$, $q$Accepts nearly any common video container or file as input and converts to modern codecs like H.264, H.265, AV1 and VP9.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Device presets$q$, $q$Built-in presets simplify encoding for specific devices, web upload, or archival quality without manual tuning.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Batch queue encoding$q$, $q$Queue multiple files for unattended conversion in one session.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Video filters$q$, $q$Deinterlacing, denoising, cropping, scaling and rotation filters improve output quality.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Hardware-accelerated encoding$q$, $q$Supports Apple VideoToolbox, Intel Quick Sync Video and NVIDIA NVENC for faster conversion on supported hardware.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Subtitle and chapter support$q$, $q$Handles subtitle passthrough and burn-in along with chapter markers and multiple audio tracks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Command-line interface$q$, $q$HandBrakeCLI enables scripting and automation of video conversion pipelines.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Cross-platform availability$q$, $q$Runs natively on Windows, macOS and Linux.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Completely free and open source with no ads or paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Cross-platform support for Windows, macOS and Linux$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Wide codec and container format support$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Active development and community since 2003$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Hardware-accelerated encoding speeds up conversions$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Interface can feel technical for complete beginners$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$No built-in DVD or Blu-ray decryption, requiring a separate library for encrypted discs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$No official mobile apps for iOS or Android$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Encoding speed depends heavily on available hardware$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$No cloud storage or collaboration features$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Is HandBrake free?$q$, $q$Yes, HandBrake is completely free and open source, with no paid tiers, subscriptions or feature restrictions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$What video formats does HandBrake support?$q$, $q$HandBrake accepts nearly any common video source as input and can output to modern codecs including H.264, H.265, AV1, VP8 and VP9, typically wrapped in MP4 or MKV containers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Does HandBrake work on Mac and Linux?$q$, $q$Yes, HandBrake runs natively on Windows, macOS and Linux.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Can HandBrake rip encrypted DVDs?$q$, $q$HandBrake does not include DVD or Blu-ray decryption logic by default to remain legally distributable, so encrypted discs typically require a separate library such as libdvdcss.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Is there a command-line version of HandBrake?$q$, $q$Yes, HandBrakeCLI is a separate command-line interface that supports scripting and automated batch video conversion.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Who maintains HandBrake?$q$, $q$HandBrake is maintained by volunteer open source contributors rather than a company, with development ongoing on GitHub since the project's creation in 2003.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Personal media conversion$q$, $q$Home users convert DVDs and downloaded video files into space-efficient formats for storage or playback on phones and tablets.$q$, $q$Home users managing personal media libraries$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Content creation and web delivery$q$, $q$Content creators and video editors compress and reformat footage for web upload or mobile delivery.$q$, $q$Content creators and video editors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$Automated batch conversion$q$, $q$Developers and IT teams use HandBrakeCLI to script and automate large-scale video conversion pipelines.$q$, $q$Developers and IT professionals automating video workflows$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$HandBrake$q$, $q$Free$q$, $q$Free, open source, no billing$q$, NULL, $q$["Unlimited video conversions","All codecs and container formats supported","Batch queue encoding","Command-line interface (HandBrakeCLI)","No ads, watermarks or feature restrictions"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HandBrake is a free, open source video transcoder that converts video from nearly any format into modern codecs such as H.264, H.265, AV1 and VP9, distributed under the GPLv2 license and available on Windows, macOS and Linux.$q$, $q$Originally created in 2003 by Eric Petit for BeOS, HandBrake was later revived and extended by community developers who added H.264 support, reaching its first stable 1.0.0 release in December 2016 after more than a decade of volunteer-driven development.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$HandBrake accepts nearly any video source as input and offers device-specific presets, a batch queue for converting multiple files, and a filter chain for deinterlacing, denoising, cropping and scaling.$q$, $q$Hardware-accelerated encoding via Apple VideoToolbox, Intel Quick Sync and NVIDIA NVENC speeds up conversion, while a separate command-line interface, HandBrakeCLI, supports scripting and automated batch workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HandBrake is completely free to download and use, with no paid tiers, subscriptions, watermarks or feature restrictions.$q$, $q$As a volunteer-maintained open source project, it relies on donations rather than sales, and its source code is publicly available on GitHub for anyone to inspect or modify.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5193cb21-ed1a-4efa-8952-c3400dfcbad7', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Passkey authentication$q$, $q$Native FIDO2/WebAuthn passkey registration and login built on the founding team's years of standards implementation experience.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Passwordless and password login$q$, $q$Supports passwords, passwordless email/magic-link login, and passkeys side by side for gradual migration.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Social SSO$q$, $q$Login via Google, Apple and other social identity providers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Multi-factor authentication$q$, $q$Adds an additional verification layer on top of passkey or password login.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Open source, self-hostable core$q$, $q$The core authentication server is open source and can be self-hosted for full data control.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Admin dashboard and Admin API$q$, $q$Manage users, projects and settings through a dashboard or programmatically via the Admin API.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Webhooks and custom SMTP$q$, $q$React to authentication events with webhooks and route transactional email through custom SMTP.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$SAML SSO$q$, $q$Optional enterprise identity federation available as an add-on on the Pro and Enterprise plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Generous free tier with 10,000 monthly active users included$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Open source with a self-hosting option for full data control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Passkey-first design reduces phishing and credential-stuffing risk$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Simple integration via lightweight API and SDKs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Startup program offers up to 1 million free MAUs for qualifying companies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$SAML SSO costs extra at $49/month per connection$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Smaller ecosystem and community compared to Auth0 or Clerk$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Enterprise pricing is not publicly listed$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Relatively young, small company compared to larger incumbents$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Open source history is short, dating only to 2022$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$What is Hanko?$q$, $q$Hanko is an open source authentication platform focused on passkeys, offering passwordless login, passwords, social SSO and multi-factor authentication via a hosted cloud service or self-hosted core.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Is Hanko open source?$q$, $q$Yes, Hanko's core authentication server became open source in 2022 and can be self-hosted, while Hanko Cloud offers the same functionality as a managed service.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$How much does Hanko cost?$q$, $q$Hanko's Starter plan is free for up to 10,000 monthly active users. The Pro plan costs $29/month plus $0.01 per MAU beyond 10,000, and Enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$What are passkeys and why does Hanko use them?$q$, $q$Passkeys are a FIDO2/WebAuthn-based passwordless login standard that replace passwords with device-based cryptographic credentials, reducing phishing and credential-stuffing risk, which is why Hanko built its platform around them.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Can I self-host Hanko?$q$, $q$Yes, Hanko's core authentication server is open source and can be self-hosted for teams that need full control over their authentication data.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$What counts as a monthly active user in Hanko's pricing?$q$, $q$Hanko defines a monthly active user as any user who is issued a session token at least once during a given month.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Passkey-first login for startups$q$, $q$Startups add passkey-based login to new products without building WebAuthn infrastructure from scratch.$q$, $q$Early-stage startups building new authentication flows$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Reducing phishing and credential-stuffing risk$q$, $q$SaaS companies replace legacy password authentication with passkeys to cut down on phishing and credential-stuffing attacks.$q$, $q$SaaS companies focused on account security$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Self-hosted, compliant authentication$q$, $q$Developers needing full data control self-host Hanko's open source core instead of relying on a third-party-hosted identity provider.$q$, $q$Developers with data residency or compliance requirements$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Starter$q$, $q$Free$q$, $q$Free, up to 10,000 MAU$q$, NULL, $q$["2 projects","Passkeys, passwords and passwordless login","Social SSO","Multi-factor authentication","Custom domain","Admin dashboard","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Pro$q$, $q$$29/month plus $0.01 per MAU over 10,000$q$, $q$Monthly$q$, NULL, $q$["5 projects","Email and Slack support","Team member invites","Webhooks","Admin API","Custom SMTP","Optional SAML SSO for $49/month per connection"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Enterprise$q$, $q$Custom, volume discounts available$q$, $q$Annual contract$q$, NULL, $q$["Unlimited projects","99.99% uptime SLA","Priority support","Admin dashboard SSO","Extended audit log retention","Commercial license option","Private cloud deployment"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$Startup Plan$q$, $q$Free, up to 1,000,000 MAU$q$, $q$Application required$q$, NULL, $q$["All Starter and Pro capabilities for qualifying early-stage startups"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hanko is an open source, developer-first authentication platform built around passkeys, offering passwordless login, traditional passwords, social SSO and multi-factor authentication through a hosted cloud service or self-hosted core.$q$, $q$Founded in Kiel, Germany, in 2018 by Felix Magedanz, Hanko began as a closed-source enterprise vendor before making its authentication server open source in 2022 and raising a venture round in 2023.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hanko's primary differentiator is native passkey (FIDO2/WebAuthn) support alongside fallback password, passwordless email and social SSO login options, delivered via a lightweight HTTP API and client SDKs.$q$, $q$The platform also includes multi-factor authentication, an admin dashboard and Admin API, webhooks, custom domains, custom SMTP, and optional SAML SSO for enterprise identity federation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hanko's free Starter plan includes up to 10,000 monthly active users across 2 projects with no credit card required, while the Pro plan costs $29/month plus $0.01 per MAU beyond 10,000.$q$, $q$Enterprise pricing is custom with an uptime SLA and private cloud deployment, and a Startup Plan grants up to 1 million free MAUs to qualifying early-stage companies.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d7124bf7-efbe-423b-8a94-15a5db73d353', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
