INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$AI Copilot suite$q$, $q$Provides instant answer suggestions, resolution recommendations, response drafting and automatic urgency prioritization.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Omnichannel ticketing$q$, $q$Consolidates email, live chat, phone and social media interactions into a single unified queue.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Self-service knowledge base$q$, $q$Lets customers resolve common issues on their own through a searchable help center.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Workflow automation$q$, $q$Automatically routes, escalates and assigns tickets to reduce manual agent work.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Real-time analytics and reporting$q$, $q$Dashboards deliver insights into ticket volume, agent performance and resolution times.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Unlimited-agent pricing option$q$, $q$Flat annual fee with a fixed ticket allowance for larger teams instead of per-agent billing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$100+ integrations$q$, $q$Native connections to Slack, Salesforce, Jira, Microsoft products and more.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Mobile apps$q$, $q$iOS and Android apps let agents manage tickets from anywhere.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Bootstrapped, profitable company with a strong track record$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Unlimited-agent pricing option for larger support teams$q$, 1);
