INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$14-day free trial with no credit card required$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Rated highly for ease of use on G2$q$, 4);
