INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$What is HappyFox used for?$q$, $q$HappyFox is used by customer service, IT and HR teams to manage support tickets across email, chat, phone and social channels from one unified platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$How much does HappyFox cost?$q$, $q$HappyFox Help Desk starts at $24 per agent per month on the Basic plan, with Team at $49 and Pro at $99 per agent per month, plus a custom-priced Enterprise Pro tier and flat-fee Unlimited Agent plans for larger teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Does HappyFox offer a free trial?$q$, $q$Yes, every HappyFox plan includes a 14-day free trial with no credit card required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$What is HappyFox AI Copilot?$q$, $q$AI Copilot is HappyFox's AI-powered suite that provides instant answer suggestions, resolution recommendations, response drafting assistance and automatic urgency prioritization for support agents.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Does HappyFox support IT and HR use cases beyond customer support?$q$, $q$Yes, HappyFox is used by IT and HR teams as well as customer support, with a Service Desk product built for ITIL-style IT support alongside the core Help Desk.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Are there unlimited-agent pricing options?$q$, $q$Yes, HappyFox offers Unlimited Agent plans that charge a flat annual fee with a fixed yearly ticket allowance, which tends to be more economical for teams above roughly 20 to 25 agents.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Omnichannel customer support$q$, $q$Support teams consolidate email, chat, phone and social tickets into one queue with HappyFox Help Desk.$q$, $q$Customer service teams handling multi-channel support$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Internal IT and HR helpdesks$q$, $q$IT and HR departments use HappyFox Service Desk and Help Desk to manage internal employee requests separately from customer support.$q$, $q$Internal IT and HR support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Scaling support teams with flat pricing$q$, $q$Growing companies use Unlimited Agent plans to avoid unpredictable per-seat cost growth as their support team expands.$q$, $q$Growing companies with large or high-volume support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Basic$q$, $q$$24/agent/month$q$, $q$Monthly or annual (annual saves ~20%)$q$, NULL, $q$["Up to 5 agents","Core ticketing","Knowledge base","Email support channel"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Team$q$, $q$$49/agent/month$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited agents","Omnichannel support","Automation and workflows","Reporting and analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Pro$q$, $q$$99/agent/month$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited agents","AI Copilot suite","Advanced automation","Advanced analytics and BI integration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Enterprise Pro$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["Unlimited agents","Custom SLAs","Dedicated support","Advanced security and compliance controls"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$Unlimited Agent Plans$q$, $q$Flat annual fee with a fixed yearly ticket allowance$q$, $q$Annual$q$, NULL, $q$["Unlimited agents","Predictable flat pricing for large or high-volume teams"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HappyFox is a cloud-based help desk and customer support suite that unifies email, chat, phone and social ticketing for customer service, IT and HR teams, delivered through a shared ticketing backbone with separately licensed add-on modules.$q$, $q$Founded in 2011 by Shalin Jain and headquartered in Irvine, California, HappyFox has remained bootstrapped without outside venture funding, reporting roughly $20 million in revenue in 2024 with about 120 employees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$An AI Copilot suite provides instant answer suggestions, resolution recommendations and automatic urgency prioritization, layered on top of an omnichannel inbox that consolidates email, chat, phone and social interactions.$q$, $q$A self-service knowledge base, workflow automation, real-time analytics and role-based access controls round out the platform, which integrates with over 100 tools including Slack, Salesforce and Jira.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HappyFox Help Desk starts at $24 per agent per month on the Basic plan (capped at 5 agents), scaling to Team at $49 and Pro at $99 per agent per month with unlimited agents, plus custom Enterprise Pro pricing.$q$, $q$Unlimited Agent plans charge a flat annual fee with a fixed ticket allowance for larger teams, and every plan includes a 14-day free trial with no credit card required.$q$]::text[], 2);
