INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Event-driven architecture$q$, $q$Node.js's non-blocking I/O model lets a single process handle thousands of simultaneous SMTP connections.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$JavaScript plugin system$q$, $q$Plugins hook into every stage of the SMTP transaction to inspect, modify, accept or reject messages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$DKIM signing and verification$q$, $q$Built-in support for signing and verifying DKIM to authenticate outbound and inbound mail.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$DNS blocklist checking$q$, $q$Plugins check DNSBLs to filter known spam and abuse sources before accepting mail.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Spam and antivirus integration$q$, $q$Integrates with SpamAssassin, rspamd and ClamAV for spam scoring and malware scanning.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Flexible deployment modes$q$, $q$Runs as an inbound filtering gateway in front of Postfix or as a full outbound mail submission agent.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$High connection throughput$q$, $q$Handles thousands of concurrent connections and messages per second in production.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$MIT licensed and free$q$, $q$Fully open source with no cost, commercial edition or licensing restrictions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Free and open source under the permissive MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Handles very high SMTP connection volume and throughput$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Highly extensible through a JavaScript plugin architecture$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Long track record in production since 2011$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Battle-tested at scale by companies like Craigslist$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Requires Node.js and JavaScript expertise to configure and extend$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$No official graphical management dashboard$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Documentation is community-maintained and can be sparse in places$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Not a hosted or managed SaaS, so self-hosting carries operational burden$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Smaller community and install base than Postfix or Exim$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$What is Haraka?$q$, $q$Haraka is a free, open source SMTP mail server written in Node.js, designed for high-throughput, asynchronous mail handling with a fully extensible JavaScript plugin architecture.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Is Haraka free?$q$, $q$Yes, Haraka is completely free and open source under the MIT license, with no paid tiers or commercial edition.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Who maintains Haraka?$q$, $q$Haraka was created by Matt Sergeant and is now community-maintained on GitHub, currently led by maintainer Matt Simerson.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$What is Haraka used for?$q$, $q$Haraka is used to operate high-throughput inbound mail filtering gateways or outbound mail submission agents, and is used in production by companies like Craigslist.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Does Haraka support spam filtering?$q$, $q$Yes, Haraka integrates with SpamAssassin and rspamd for spam scoring and supports DNS blocklist checking through plugins.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Can I write custom plugins for Haraka?$q$, $q$Yes, Haraka's behavior is customized entirely through JavaScript plugins that hook into each stage of the SMTP transaction.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$High-throughput inbound mail filtering$q$, $q$Companies use Haraka as a filtering gateway that validates and forwards inbound mail to a downstream MTA like Postfix, as Craigslist does in production.$q$, $q$Engineering teams operating high-volume inbound mail infrastructure$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Custom transactional email infrastructure$q$, $q$Developers build custom outbound mail pipelines using Haraka's plugin system instead of relying entirely on third-party email service providers.$q$, $q$Developers building transactional email systems$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Self-hosted, extensible MTA$q$, $q$Organizations that want full control over mail-handling logic self-host Haraka instead of using a commercial ESP.$q$, $q$Organizations wanting a self-hosted, programmable mail server$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$Haraka$q$, $q$Free$q$, $q$Free, open source, no billing$q$, NULL, $q$["Unlimited self-hosted deployment","Full plugin ecosystem access","MIT license, no usage restrictions","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Haraka is a free, open source SMTP mail server written in Node.js, built for high-throughput, asynchronous mail handling with a fully extensible JavaScript plugin architecture, released under the MIT license.$q$, $q$Created by Matt Sergeant in 2011 and inspired by the Qpsmtpd mail server, Haraka is community-maintained on GitHub with no corporate owner, currently led by maintainer Matt Simerson.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Haraka's event-driven, non-blocking architecture lets a single server process handle thousands of simultaneous SMTP connections, with behavior customized entirely through JavaScript plugins hooked into each stage of the SMTP transaction.$q$, $q$A large plugin registry covers authentication, DKIM signing, DNS blocklist checking, SpamAssassin and rspamd integration, and ClamAV antivirus scanning, and Haraka can run as either an inbound filtering gateway or an outbound submission agent.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Haraka is completely free and open source under the MIT license, with no paid tiers, commercial edition or vendor lock-in.$q$, $q$Anyone can download, modify, self-host and redistribute Haraka without cost, and there is no company selling a hosted or supported commercial version.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
