INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9af66bbf-b130-4408-9f34-c92e212205a4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Vulnerability scanning$q$, $q$Integrates with scanners like Trivy or Clair to automatically analyze stored images for known vulnerabilities.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Content trust and image signing$q$, $q$Supports Notary and Cosign integration so consumers can verify an image's provenance and integrity before deployment.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Role-based access control$q$, $q$Granular, project-based access control that integrates with LDAP, Active Directory and OIDC identity providers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Multi-tenancy with projects$q$, $q$Organizes images into isolated projects for different teams or applications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Cross-registry replication$q$, $q$Mirrors images between multiple Harbor instances or across clouds for redundancy and distribution.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Helm chart repository$q$, $q$Built-in storage for Helm charts and other Kubernetes packaging artifacts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Retention and garbage collection$q$, $q$Automated policies manage image retention and reclaim storage space.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Web UI and REST API$q$, $q$Full web-based management console alongside an API for CI/CD pipeline integration.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$CNCF Graduated project with strong governance and wide adoption$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Completely free and open source under Apache 2.0$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Enterprise-grade security scanning and image signing built in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Backed by contributions from more than 680 organizations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Deploys on any Kubernetes cluster or Docker-capable system$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Requires self-hosting and ongoing operational management$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Initial setup and configuration can be complex for smaller teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Can be resource-intensive at large scale$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Upgrades between major versions require careful planning$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Relies on external scanners like Trivy for vulnerability detection$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$What is Harbor?$q$, $q$Harbor is an open source, CNCF-graduated container registry that stores, scans and signs container images and OCI artifacts with role-based access control for Kubernetes environments.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Is Harbor free?$q$, $q$Yes, Harbor is entirely free and open source under the Apache 2.0 license, with organizations only paying for their own hosting infrastructure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Who maintains Harbor?$q$, $q$Harbor originated at VMware in 2014, was open sourced in 2016, and is now governed as a CNCF Graduated project with contributions from more than 680 organizations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Can Harbor replace Docker Hub?$q$, $q$Yes, many organizations use Harbor as a private, self-hosted alternative to public registries like Docker Hub, particularly when they need built-in vulnerability scanning and access control.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Does Harbor support Kubernetes natively?$q$, $q$Yes, Harbor is designed to deploy on any Kubernetes environment via an official Helm chart, or on a system with Docker support.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$What is Harbor's relationship to CNCF and VMware?$q$, $q$Harbor was created at VMware in 2014, open sourced in 2016, and joined the Cloud Native Computing Foundation in 2018, graduating in June 2020 as the first open source container registry to reach that status.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Private enterprise container registry$q$, $q$Enterprises deploy Harbor as a secure, private registry for storing and distributing container images across Kubernetes clusters.$q$, $q$Platform engineering and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Regulated industry compliance$q$, $q$Organizations in finance, telecom and other regulated sectors use Harbor's scanning and signing features to meet image provenance and compliance requirements.$q$, $q$Regulated industries requiring image security compliance$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Internal developer platforms$q$, $q$Platform teams build multi-tenant internal developer platforms using Harbor's project-based access control and replication features.$q$, $q$Platform teams building internal developer platforms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$Harbor (Self-Hosted)$q$, $q$Free$q$, $q$Free, open source, no billing$q$, NULL, $q$["Unlimited self-hosted deployment","Vulnerability scanning integration","Image signing and content trust","Role-based access control","Cross-registry replication","Helm chart repository support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Harbor is an open source, cloud-native container registry that stores, scans and signs container images and OCI artifacts, giving organizations a private, security-focused alternative to public registries like Docker Hub.$q$, $q$Originally built inside VMware's China R&D organization in 2014 and open sourced in 2016, Harbor joined the CNCF in 2018 and became a CNCF Graduated project in June 2020, the first open source container registry to reach that status.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Harbor integrates vulnerability scanners like Trivy or Clair to analyze stored images, and supports content trust and image signing through tools like Notary and Cosign so consumers can verify image provenance before deployment.$q$, $q$Its multi-tenant project model provides granular role-based access control integrated with LDAP, Active Directory and OIDC, alongside cross-registry replication, a built-in Helm chart repository, and retention and garbage collection policies.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2fda9f09-2141-4cc7-84c4-66606e716a87', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Harbor is entirely free and open source under the Apache 2.0 license, with no paid tier or usage limit imposed by the project itself.$q$, $q$Organizations self-host Harbor on their own Kubernetes clusters or infrastructure and pay only their own compute and storage costs; some vendors offer managed or supported Harbor deployments as separate commercial services.$q$]::text[], 2);
